#include <bits/stdc++.h>
using namespace std;

long long solve(string s, vector<long long> order, long long k) {
    int n = s.length();
    long long total_substrings = n * (n + 1) / 2;
    set<int> stars;
    long long current_sum = total_substrings;
    for (int t = 0; t < n; ++t) {
        int pos = order[t];
        set<int>::iterator it = stars.lower_bound(pos);
        int prev = (it == stars.begin() ? -1 : *(--it));
        int next = (it == stars.end() ? n : *it);
        int original_length = next - prev - 1;
        long long original_contribution = original_length * (original_length + 1) / 2;
        current_sum -= original_contribution;
        int left_length;
        if (prev == -1) {
            left_length = pos;
        } else {
            left_length = pos - prev - 1;
        }
        int right_length;
        if (next == n) {
            right_length = n - pos - 1;
        } else {
            right_length = next - pos - 1;
        }
        long long left_contribution = left_length * (left_length + 1) / 2;
        long long right_contribution = right_length * (right_length + 1) / 2;
        current_sum += left_contribution + right_contribution;
        stars.insert(pos);
        long long valid_count = total_substrings - current_sum;
        if (valid_count >= k) {
            return t;
        }
    }
    return -1;
}

