function solve(s, order, k) {
    const n = s.length;
    const total_substrings = n * (n + 1) / 2;
    let current_sum = total_substrings;
    let sortedArr = [];
    for (let t = 0; t < n; t++) {
        const pos = order[t];
        let left = 0, right = sortedArr.length;
        while (left < right) {
            const mid = Math.floor((left + right) / 2);
            if (sortedArr[mid] < pos) {
                left = mid + 1;
            } else {
                right = mid;
            }
        }
        const insertionIndex = left;
        let prev = -1;
        if (insertionIndex > 0) {
            prev = sortedArr[insertionIndex - 1];
        }
        let next = n;
        if (insertionIndex < sortedArr.length) {
            next = sortedArr[insertionIndex];
        }
        const original_length = next - prev - 1;
        const original_contribution = original_length * (original_length + 1) / 2;
        current_sum -= original_contribution;
        let left_length;
        if (prev === -1) {
            left_length = pos;
        } else {
            left_length = pos - prev - 1;
        }
        let right_length;
        if (next === n) {
            right_length = n - pos - 1;
        } else {
            right_length = next - pos - 1;
        }
        const left_contribution = left_length * (left_length + 1) / 2;
        const right_contribution = right_length * (right_length + 1) / 2;
        current_sum += left_contribution + right_contribution;
        sortedArr.splice(insertionIndex, 0, pos);
        const valid_count = total_substrings - current_sum;
        if (valid_count >= k) {
            return t;
        }
    }
    return -1;
}
